import{_ as t,o as a,c as l,a0 as r}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Delete an Import & Roll Back Its Changes","description":"","frontmatter":{},"headers":[],"relativePath":"imports/delete-and-rollback.md","filePath":"imports/delete-and-rollback.md"}'),o={name:"imports/delete-and-rollback.md"};function i(s,e,n,h,d,c){return a(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="delete-an-import-roll-back-its-changes" tabindex="-1">Delete an Import &amp; Roll Back Its Changes <a class="header-anchor" href="#delete-an-import-roll-back-its-changes" aria-label="Permalink to &quot;Delete an Import &amp; Roll Back Its Changes&quot;">​</a></h1><p>Use delete-with-results when an already applied import was wrong and you want the tracker to undo the changes that import recorded.</p><blockquote><p>Screenshot placeholder: import-delete-impact.png</p></blockquote><h2 id="the-walkthrough" tabindex="-1">The walkthrough <a class="header-anchor" href="#the-walkthrough" aria-label="Permalink to &quot;The walkthrough&quot;">​</a></h2><ol><li>Open the import.</li><li>Review the rollback impact preview.</li><li>Confirm <strong>Delete import &amp; rollback</strong>.</li><li>The import moves to <code>rolled_back</code>.</li><li>It then lives in the Recycle Bin until restored or left deleted.</li></ol><h2 id="what-the-impact-preview-is-for" tabindex="-1">What the impact preview is for <a class="header-anchor" href="#what-the-impact-preview-is-for" aria-label="Permalink to &quot;What the impact preview is for&quot;">​</a></h2><p>The delete dialog warns that rollback only targets data created or changed by this import.</p><p>That means the preview is there to show what the app believes it can safely undo before you confirm.</p><h2 id="what-rollback-really-guarantees" tabindex="-1">What rollback really guarantees <a class="header-anchor" href="#what-rollback-really-guarantees" aria-label="Permalink to &quot;What rollback really guarantees&quot;">​</a></h2><p>The real guarantee is narrower than &quot;rewind everything no matter what.&quot;</p><p>Today, rollback works like this:</p><ul><li>results created by the import can be removed</li><li>overwritten results can be restored to their previous value <strong>if nothing newer has changed them since</strong></li><li>player field changes can be reverted <strong>if the current value still matches what this import wrote</strong></li><li>players created only by this import may be soft-deleted when safe</li></ul><p>If something newer changed the same result or field after the import, rollback skips that piece instead of blindly erasing newer work.</p><h2 id="what-rollback-does-not-do" tabindex="-1">What rollback does not do <a class="header-anchor" href="#what-rollback-does-not-do" aria-label="Permalink to &quot;What rollback does not do&quot;">​</a></h2><p>Rollback is not allowed to casually remove unrelated data from:</p><ul><li>other imports</li><li>manual entry</li><li>newer edits</li></ul><p>That safety rule is why some overwritten values can be restored only when the current state still matches the import&#39;s own write.</p><h2 id="plain-delete-vs-rollback-delete" tabindex="-1">Plain delete vs rollback delete <a class="header-anchor" href="#plain-delete-vs-rollback-delete" aria-label="Permalink to &quot;Plain delete vs rollback delete&quot;">​</a></h2><p>Use plain delete only for imports you are discarding as imports.</p><p>Use <strong>delete-with-results</strong> when you need to undo tracked applied changes.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./restore-import.html">Restore a Deleted Import</a></li><li><a href="./import-mistakes.html">Fixing Import Mistakes</a></li></ul>',22)])])}const u=t(o,[["render",i]]);export{m as __pageData,u as default};
